#!/usr/bin/env node
/**
 * COBTEL.com 产品抓取脚本
 *
 * 用法（在项目根目录 PowerShell 里执行）：
 *   node scripts/scrape-cobtel.mjs
 *
 * 输出：
 *   data/products.json          — 产品数据
 *   public/products/*.jpg|webp  — 产品图片
 *
 * 依赖：项目里已装的 playwright（首次运行会自动安装 chromium 浏览器）
 */

import { chromium } from 'playwright'
import { writeFile, mkdir, access } from 'node:fs/promises'
import { fileURLToPath } from 'node:url'
import { dirname, join, resolve } from 'node:path'
import { setTimeout as sleep } from 'node:timers/promises'

const __dirname = dirname(fileURLToPath(import.meta.url))
const PROJECT_ROOT = resolve(__dirname, '..')
const DATA_DIR = join(PROJECT_ROOT, 'data')
const IMG_DIR = join(PROJECT_ROOT, 'public', 'products')
const OUTPUT_JSON = join(DATA_DIR, 'products.json')

const BASE_URL = 'https://www.cobtel.com'
const USER_AGENT =
  'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36'

/** 等待直到目录存在 */
async function ensureDir(dir) {
  try {
    await access(dir)
  } catch {
    await mkdir(dir, { recursive: true })
  }
}

/** 从 URL 下载图片到本地 */
async function downloadImage(page, url, fileName) {
  try {
    const resp = await page.request.get(url, { headers: { 'User-Agent': USER_AGENT } })
    if (!resp.ok()) throw new Error(`HTTP ${resp.status()}`)
    const buffer = await resp.body()
    const filePath = join(IMG_DIR, fileName)
    await writeFile(filePath, buffer)
    return `/products/${fileName}`
  } catch (e) {
    console.warn(`  ⚠️ 图片下载失败 ${url}: ${e.message}`)
    return null
  }
}

/** 从 srcset 或 src 中选最大图 */
function pickBestImage(src, srcset) {
  if (srcset) {
    const parts = srcset.split(',').map((s) => s.trim().split(' '))
    const largest = parts[parts.length - 1]
    if (largest && largest[1]) return largest[0]
  }
  return src || null
}

/** 抓取首页 — 找出所有产品分类链接 */
async function discoverCategories(page) {
  console.log('🔍 步骤 1: 抓取首页，发现产品分类...')
  await page.goto(BASE_URL, { waitUntil: 'networkidle', timeout: 60000 })

  // 尝试多种常见的产品链接选择器
  const links = await page.evaluate(() => {
    const selectors = [
      'a[href*="/product"]',
      'a[href*="/products"]',
      'a[href*="/category"]',
      'a[href*="/Product"]',
      'a[href*="/Products"]',
      '.product-item a',
      '.product-card a',
      '.cat-item a',
    ]
    const urls = new Set()
    for (const sel of selectors) {
      document.querySelectorAll(sel).forEach((a) => {
        const href = a.getAttribute('href')
        if (href && !href.startsWith('#') && !href.startsWith('javascript:')) {
          urls.add(href.startsWith('http') ? href : new URL(href, location.href).href)
        }
      })
    }
    return Array.from(urls)
  })

  console.log(`  ✓ 发现 ${links.length} 个候选链接`)
  // 过滤：只保留 COBTEL 域名内的链接
  return links.filter((u) => u.includes('cobtel.com'))
}

/** 抓取分类页 — 获取产品列表 */
async function discoverProductsInCategory(page, categoryUrl) {
  console.log(`🔍 抓取分类: ${categoryUrl}`)
  await page.goto(categoryUrl, { waitUntil: 'networkidle', timeout: 60000 })
  await sleep(1000)

  const products = await page.evaluate(() => {
    const out = []
    // 常见的产品卡片选择器
    const cards = document.querySelectorAll(
      '.product-item, .product-card, .product, .item, [class*="product-list"] > *, .goods-item, .pro-item',
    )
    cards.forEach((card) => {
      const link =
        card.querySelector('a')?.getAttribute('href') ||
        card.closest('a')?.getAttribute('href')
      if (!link) return
      const url = link.startsWith('http') ? link : new URL(link, location.href).href
      const img = card.querySelector('img')
      const name =
        card.querySelector('.product-name, .title, h3, h4, .name, [class*="name"]')
          ?.textContent?.trim() ||
        img?.getAttribute('alt') ||
        ''
      out.push({ url, name, image: pickBestImage(img?.src, img?.getAttribute('srcset')) })
    })
    return out
  })

  console.log(`  ✓ 分类下发现 ${products.length} 个产品`)
  return products
}

/** 抓取单个产品详情页 */
async function scrapeProductDetail(page, url) {
  console.log(`  📦 抓取产品: ${url}`)
  await page.goto(url, { waitUntil: 'networkidle', timeout: 60000 })
  await sleep(800)

  const data = await page.evaluate(() => {
    const text = (sel) => document.querySelector(sel)?.textContent?.trim() || ''
    const attr = (sel, a) => document.querySelector(sel)?.getAttribute(a) || ''

    // 标题
    const name = (
      text('h1.product-title, h1.product-name, h1.detail-title, .product-detail h1, h1') ||
      attr('meta[property="og:title"]', 'content')
    ).trim()

    // 描述
    let description = ''
    const descSelectors = [
      '.product-description',
      '.product-detail-description',
      '.description',
      '[class*="description"]',
      '.product-intro',
      '.product-content',
    ]
    for (const sel of descSelectors) {
      const el = document.querySelector(sel)
      if (el && el.textContent.trim().length > 20) {
        description = el.innerHTML.trim()
        break
      }
    }
    if (!description) {
      const og = attr('meta[property="og:description"]', 'content')
      if (og) description = og
    }

    // 图片
    const images = []
    const imgSelectors = [
      '.product-gallery img',
      '.gallery img',
      '.product-images img',
      '.swiper img',
      '.product-photo img',
      '[class*="gallery"] img',
      '[class*="slider"] img',
    ]
    const seenSrc = new Set()
    imgSelectors.forEach((sel) => {
      document.querySelectorAll(sel).forEach((img) => {
        const src = pickBestImage(img.src || img.getAttribute('data-src'), img.getAttribute('srcset'))
        if (src && !seenSrc.has(src)) {
          seenSrc.add(src)
          images.push({ src, alt: img.alt || name })
        }
      })
    })
    // fallback: og:image
    if (images.length === 0) {
      const ogImg = attr('meta[property="og:image"]', 'content')
      if (ogImg) images.push({ src: ogImg, alt: name })
    }

    // 规格表
    const specs = []
    const specSelectors = [
      '.product-specs tr',
      '.specifications tr',
      '.spec-table tr',
      'table.spec tr',
      '[class*="spec"] tr',
      '.product-attributes tr',
    ]
    specSelectors.forEach((sel) => {
      document.querySelectorAll(sel).forEach((row) => {
        const cells = row.querySelectorAll('th, td')
        if (cells.length >= 2) {
          const key = cells[0].textContent.trim().replace(/[:：]\s*$/, '')
          const value = cells[1].textContent.trim()
          if (key && value && key.length < 50 && value.length < 200) {
            specs.push({ key, value })
          }
        }
      })
    })

    // SKU / 型号
    const sku =
      text('.product-sku, .sku, [class*="sku"]') ||
      attr('meta[itemprop="productID"], meta[itemprop="mpn"]', 'content') ||
      ''

    // 分类
    const breadcrumbs = Array.from(
      document.querySelectorAll('.breadcrumb a, .breadcrumbs a, [class*="breadcrumb"] a'),
    )
      .map((a) => a.textContent.trim())
      .filter(Boolean)

    return { name, description, images, specs, sku, breadcrumbs, pageHtml: document.title }
  })

  return { ...data, sourceUrl: url }
}

/** 主流程 */
async function main() {
  console.log('🚀 启动 COBTEL 产品抓取')
  console.log('='.repeat(60))

  await ensureDir(DATA_DIR)
  await ensureDir(IMG_DIR)

  const browser = await chromium.launch({
    headless: true,
    args: ['--no-sandbox', '--disable-setuid-sandbox'],
  })

  const context = await browser.newContext({
    userAgent: USER_AGENT,
    viewport: { width: 1440, height: 900 },
    locale: 'en-US',
  })

  const page = await context.newPage()

  try {
    // 1. 发现分类
    const categoryLinks = await discoverCategories(page)

    // 如果没发现分类链接，可能首页直接是产品列表
    let productList = []
    if (categoryLinks.length > 0) {
      console.log(`\n📂 步骤 2: 遍历 ${categoryLinks.length} 个分类，抓取产品列表...`)
      for (const catUrl of categoryLinks.slice(0, 30)) {
        // 最多抓 30 个分类
        try {
          const items = await discoverProductsInCategory(page, catUrl)
          productList.push(...items)
        } catch (e) {
          console.warn(`  ⚠️ 分类抓取失败 ${catUrl}: ${e.message}`)
        }
      }
    }

    // 去重
    const uniqueProducts = Array.from(
      new Map(productList.map((p) => [p.url, p])).values(),
    )
    console.log(`\n✓ 共发现 ${uniqueProducts.length} 个独立产品链接`)

    if (uniqueProducts.length === 0) {
      console.warn('\n⚠️ 没找到产品。请检查 COBTEL.com 网站结构。')
      console.log('提示：可以在浏览器打开 ' + BASE_URL + ' 看下产品是怎么展示的。')
      console.log('然后修改脚本中的选择器（grep "product-item" / "gallery" 等位置）。')
      process.exit(1)
    }

    // 3. 抓取每个产品详情
    console.log(`\n📦 步骤 3: 抓取每个产品详情（共 ${uniqueProducts.length} 个）...`)
    const detailedProducts = []
    let imgCounter = 0

    for (let i = 0; i < uniqueProducts.length; i++) {
      const p = uniqueProducts[i]
      try {
        const detail = await scrapeProductDetail(page, p.url)

        // 下载图片
        const localImages = []
        for (let j = 0; j < detail.images.length && j < 5; j++) {
          imgCounter++
          const ext = detail.images[j].src.match(/\.(jpg|jpeg|png|webp|gif)(\?|$)/i)?.[1] || 'jpg'
          const fileName = `cobtel-${Date.now()}-${imgCounter}.${ext}`
          const localPath = await downloadImage(page, detail.images[j].src, fileName)
          if (localPath) localImages.push(localPath)
        }

        if (detail.name) {
          detailedProducts.push({
            id: `cobtel-${i + 1}`,
            slug: detail.name
              .toLowerCase()
              .replace(/[^a-z0-9一-龥]+/g, '-')
              .replace(/^-|-$/g, '')
              .substring(0, 80),
            sku: detail.sku || `COBTEL-${i + 1}`,
            name: { en: detail.name, zh: detail.name },
            description: { en: detail.description || '', zh: detail.description || '' },
            category: detail.breadcrumbs[detail.breadcrumbs.length - 2] || 'General',
            images: localImages,
            specifications: detail.specs,
            sourceUrl: detail.sourceUrl,
            scrapedAt: new Date().toISOString(),
          })
          console.log(`    ✓ [${i + 1}/${uniqueProducts.length}] ${detail.name} (${localImages.length} 张图)`)
        }
      } catch (e) {
        console.warn(`    ⚠️ 抓取失败 ${p.url}: ${e.message}`)
      }

      // 礼貌延迟，避免被封
      await sleep(500)
    }

    // 4. 保存 JSON
    await writeFile(OUTPUT_JSON, JSON.stringify(detailedProducts, null, 2), 'utf-8')
    console.log(`\n✅ 完成！`)
    console.log(`   产品数据：${OUTPUT_JSON}`)
    console.log(`   产品图片：${IMG_DIR}`)
    console.log(`   共抓取：${detailedProducts.length} 个产品`)
    console.log(`\n下一步：`)
    console.log(`   1. 检查 data/products.json 内容是否完整`)
    console.log(`   2. 检查 public/products/ 下的图片是否下载成功`)
    console.log(`   3. 在 Payload 后台或代码中替换 placeholder 数据`)
  } catch (e) {
    console.error('\n❌ 抓取过程出错:', e)
    process.exit(1)
  } finally {
    await browser.close()
  }
}

main()

