function ProductsContent({ locale }: { locale: string }) {
  const t = useTranslations('products')
  const loc = locale as 'en' | 'zh'

  // 按分类分组
  const categoriesMap = new Map<string, { name: { en: string; zh: string }; products: typeof placeholderProducts }>()
  for (const product of placeholderProducts) {
    const key = product.category.slug
    if (!categoriesMap.has(key)) {
      categoriesMap.set(key, { name: product.category.name, products: [] })
    }
    categoriesMap.get(key)!.products.push(product)
  }

  const categories = Array.from(categoriesMap.entries()).map(([slug, data]) => ({
    slug,
    name: data.name,
    count: data.products.length,
    sample: data.products[0],
  }))

  return (
    <div className="container py-12 md:py-16">
      <div className="mb-10">
        <h1 className="text-3xl md:text-4xl font-bold tracking-tight">{t('title')}</h1>
        <p className="mt-2 text-muted-foreground">{t('subtitle')}</p>
      </div>

      <h2 className="text-xl font-semibold mb-6">{t('categories')}</h2>
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
        {categories.map((cat) => (
          <Link key={cat.slug} href={`/products/${cat.sample.slug}`}>
            <Card className="group hover:border-brand-300 hover:shadow-md transition-all cursor-pointer h-full overflow-hidden">
              <div className="aspect-video bg-gradient-to-br from-brand-50 to-brand-100 relative">
                <img
                  src={cat.sample.images[0]}
                  alt={cat.name[loc]}
                  className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-300"
                  loading="lazy"
                />
                <div className="absolute inset-0 bg-gradient-to-t from-black/40 to-transparent" />
                <div className="absolute bottom-3 left-3 text-white text-xs font-medium bg-black/40 backdrop-blur px-2 py-1 rounded">
                  {cat.count} {locale === 'zh' ? '款产品' : 'products'}
                </div>
              </div>
              <CardHeader>
                <div className="flex items-start justify-between">
                  <div className="h-10 w-10 rounded-lg bg-brand-100 text-brand-600 flex items-center justify-center -mt-12 relative z-10 border-4 border-background">
                    <Package className="h-5 w-5" />
                  </div>
                  <ArrowRight className="h-4 w-4 text-muted-foreground group-hover:text-brand-600 group-hover:translate-x-1 transition-all" />
                </div>
                <CardTitle className="text-lg mt-2">{cat.name[loc]}</CardTitle>
              </CardHeader>
              <CardContent>
                <p className="text-sm text-muted-foreground line-clamp-2">
                  {cat.sample.shortDescription[loc]}
                </p>
              </CardContent>
            </Card>
          </Link>
        ))}
      </div>

      {/* 所有产品列表 */}
      <div className="mt-16">
        <h2 className="text-xl font-semibold mb-6">
          {locale === 'zh' ? '全部产品' : 'All Products'}
        </h2>
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
          {placeholderProducts.map((product) => (
            <Link key={product.id} href={`/products/${product.slug}`}>
              <Card className="group hover:shadow-lg transition-shadow overflow-hidden">
                <div className="aspect-[4/3] bg-gradient-to-br from-brand-50 to-brand-100 relative overflow-hidden">
                  <img
                    src={product.images[0]}
                    alt={product.name[loc]}
                    className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-300"
                    loading="lazy"
                  />
                  <div className="absolute top-2 left-2 text-[10px] uppercase tracking-wider font-medium bg-white/90 backdrop-blur px-2 py-1 rounded">
                    {product.category.name[loc]}
                  </div>
                </div>
                <CardHeader className="pb-2">
                  <CardTitle className="text-sm leading-snug line-clamp-2 group-hover:text-primary transition-colors">
                    {product.name[loc]}
                  </CardTitle>
                </CardHeader>
                <CardContent className="pt-0">
                  <p className="text-xs text-muted-foreground font-mono">{product.sku}</p>
                </CardContent>
              </Card>
            </Link>
          ))}
        </div>
      </div>
    </div>
  )
}

