  locales: ['en', 'zh'] as const,
  defaultLocale: 'en',
  localePrefix: 'always',
  localeDetection: false,
})

// 类型化导航 API（替代 next/link）
export const { Link, redirect, usePathname, useRouter, getPathname } =
  createNavigation(routing)

import { getRequestConfig } from 'next-intl/server'
import { routing } from './routing'

export default getRequestConfig(async ({ requestLocale }) => {
  // 从 requestLocale 解析目标语言
  const requested = await requestLocale
  // next-intl 3.x 没有 hasLocale — 用 includes 手动校验
  const locale = (routing.locales as readonly string[]).includes(requested || '')
    ? (requested as 'en' | 'zh')
    : routing.defaultLocale

  return {
    locale,
    messages: (await import(`./messages/${locale}.json`)).default,
  }
})

import createMiddleware from 'next-intl/middleware'
import { routing } from '@/i18n/routing'

export default createMiddleware(routing)

export const config = {
  // 跳过 Next.js 内部路由、静态资源、API、Payload admin
  matcher: [
    '/((?!api|_next|_vercel|admin|.*\\..*).*)',
  ],
}

'use client'

import { useLocale } from 'next-intl'
import { useRouter, usePathname } from '@/i18n/routing'
import { Globe } from 'lucide-react'
import { Button } from '@/components/ui/button'

const languages = {
  en: { label: 'English', short: 'EN', flag: '🇺🇸' },
  zh: { label: '中文', short: '中', flag: '🇨🇳' },
} as const

export function LangSwitcher() {
  const locale = useLocale() as keyof typeof languages
  const router = useRouter()
  const pathname = usePathname()

  const otherLocale = locale === 'en' ? 'zh' : 'en'

  return (
    <Button
      variant="ghost"
      size="sm"
      onClick={() => router.replace(pathname, { locale: otherLocale })}
      className="gap-2"
      aria-label="Switch language"
    >
      <Globe className="h-4 w-4" />
      <span className="font-medium">{languages[otherLocale].short}</span>
    </Button>
  )
}

