  'rj45-connector', 'rj45-connector', 'rj45-connector',
  'keystone-jack',  'keystone-jack',
  'patch-panel',    'patch-panel',
  'cable-manager',
  'fiber-optic', 'fiber-optic',
  'network-cable', 'network-cable',
  'power-cable',
