      featured: false,
      order: order++,
      source: 'extra',
    })
  }

  // 4) 计算每个分类的统计
  const catStats = {}
  for (const p of products) {
    catStats[p.category] = (catStats[p.category] || 0) + 1
  }
  const categories = CATEGORIES.map((c) => ({
    ...c,
    count: catStats[c.slug] || 0,
