import { useTranslations, useLocale } from 'next-intl'
import { Link } from '@/i18n/routing'
import { ArrowRight } from 'lucide-react'
import { Button } from '@/components/ui/button'
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card'
import { getFeaturedProducts, getCategoryBySlug } from '@/lib/products'

export function FeaturedProducts() {
  const t = useTranslations('home')
  const tCommon = useTranslations('common')
  const locale = useLocale() as 'en' | 'zh'
  const products = getFeaturedProducts(8)

  return (
    <section className="py-20 md:py-24">
      <div className="container">
        <div className="flex flex-col md:flex-row md:items-end md:justify-between gap-4 mb-12">
          <div>
            <h2 className="text-3xl md:text-4xl font-bold tracking-tight">{t('featuredProducts')}</h2>
            <p className="mt-2 text-muted-foreground max-w-xl">{t('featuredProductsDesc')}</p>
          </div>
          <Button asChild variant="ghost" className="gap-2">
            <Link href="/products">
              {tCommon('viewAll')}
              <ArrowRight className="h-4 w-4" />
            </Link>
          </Button>
        </div>

        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
          {products.map((product) => {
            const cat = getCategoryBySlug(product.category)
            return (
              <Card key={product.id} className="group hover:shadow-lg transition-shadow overflow-hidden">
                <Link href={`/products/${product.slug}`}>
                  <div className="aspect-[4/3] bg-gradient-to-br from-brand-50 to-brand-100 flex items-center justify-center relative overflow-hidden">
                    <img
                      src={product.images[0]}
                      alt={product.name[locale]}
                      className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-300"
                      loading="lazy"
                    />
                    {cat && (
                      <div className="absolute top-3 left-3 text-[10px] uppercase tracking-wider font-medium bg-white/90 backdrop-blur px-2 py-1 rounded">
                        {cat.name[locale]}
                      </div>
                    )}
                  </div>
                  <CardHeader className="pb-3">
                    <CardTitle className="text-base leading-snug line-clamp-2 group-hover:text-primary transition-colors">
                      {product.name[locale]}
                    </CardTitle>
                  </CardHeader>
                  <CardContent className="pt-0">
                    <CardDescription className="line-clamp-2 text-sm">
                      {product.shortDescription?.[locale] ?? ''}
                    </CardDescription>
                  </CardContent>
                </Link>
              </Card>
            )
          })}
        </div>
      </div>
    </section>
  )
}

