                <div className="absolute inset-0 bg-gradient-to-t from-black/40 to-transparent" />
                <div className="absolute bottom-3 left-3 text-white text-xs font-medium bg-black/40 backdrop-blur px-2 py-1 rounded">
                  {cat.count} {locale === 'zh' ? '款产品' : 'products'}
                </div>
              </div>
              <CardHeader>
                <div className="flex items-start justify-between">
                  <div className="h-10 w-10 rounded-lg bg-brand-100 text-brand-600 flex items-center justify-center -mt-12 relative z-10 border-4 border-background">
                    <Package className="h-5 w-5" />
                  </div>
                  <ArrowRight className="h-4 w-4 text-muted-foreground group-hover:text-brand-600 group-hover:translate-x-1 transition-all" />
                </div>
                <CardTitle className="text-lg mt-2">{cat.name[loc]}</CardTitle>
              </CardHeader>
              <CardContent>
                <p className="text-sm text-muted-foreground line-clamp-2">
                  {cat.sample.shortDescription[loc]}
                </p>
              </CardContent>
            </Card>
          </Link>
        ))}
      </div>

      {/* 所有产品列表 */}
      <div className="mt-16">
        <h2 className="text-xl font-semibold mb-6">
          {locale === 'zh' ? '全部产品' : 'All Products'}
        </h2>
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
          {placeholderProducts.map((product) => (
            <Link key={product.id} href={`/products/${product.slug}`}>
              <Card className="group hover:shadow-lg transition-shadow overflow-hidden">
                <div className="aspect-[4/3] bg-gradient-to-br from-brand-50 to-brand-100 relative overflow-hidden">
                  <img
                    src={product.images[0]}
                    alt={product.name[loc]}
                    className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-300"
