import type { CollectionConfig } from 'payload'
import {
  authenticated,
  superAdmin,
  selfOrAdmin,
  adminAccess,
  superAdminField,
} from '../access'

export const Users: CollectionConfig = {
  slug: 'users',
  admin: {
    useAsTitle: 'email',
    defaultColumns: ['email', 'name', 'roles'],
    group: 'Admin',
  },
  auth: true,
  access: {
    create: superAdmin,
    read: authenticated,
    update: selfOrAdmin,
    delete: superAdmin,
    admin: adminAccess,
  },
  fields: [
    {
      name: 'name',
      type: 'text',
      required: true,
    },
    {
      name: 'roles',
      type: 'select',
      hasMany: true,
      required: true,
      defaultValue: ['editor'],
      options: [
        { label: 'Super Admin', value: 'super-admin' },
        { label: 'Editor', value: 'editor' },
        { label: 'Sales', value: 'sales' },
      ],
      access: {
        // 字段级只能返回 boolean
        update: superAdminField,
      },
    },
  ],
  timestamps: true,
}

import type { CollectionConfig } from 'payload'
import { anyone, authenticated } from '../access'

/**
 * Media — 产品图片、PDF 规格书、公司证书等
 * 开发期存到 public/media/，生产期切到 S3/OSS
 */
export const Media: CollectionConfig = {
  slug: 'media',
  admin: {
    useAsTitle: 'filename',
    group: 'Content',
  },
  access: {
    read: anyone,
    create: authenticated,
    update: authenticated,
    delete: authenticated,
  },
  upload: {
    staticDir: 'public/media',
    mimeTypes: ['image/*', 'application/pdf'],
    imageSizes: [
      { name: 'thumbnail', width: 200, height: 200, position: 'centre' },
      { name: 'card', width: 400, height: 300, position: 'centre' },
      { name: 'detail', width: 800, height: undefined, position: 'centre' },
      { name: 'hero', width: 1920, height: undefined, position: 'centre' },
    ],
  },
  fields: [
    {
      name: 'alt',
      type: 'text',
      required: true,
      localized: true,
      admin: {
        description: '图片 alt 文本（SEO 与无障碍）',
      },
    },
    {
      name: 'caption',
      type: 'text',
      localized: true,
    },
  ],
  timestamps: true,
}

import type { Access, FieldAccess } from 'payload'

// ============================================================
// 集合级 Access（支持返回 Where 子句做行级过滤）
// ============================================================

/** 仅已登录管理员可访问 */
export const authenticated: Access = ({ req: { user } }) => {
  return Boolean(user)
}

/** 仅超级管理员（集合级）*/
export const superAdmin: Access = ({ req: { user } }) => {
  return (user as any)?.roles?.includes('super-admin') || false
}

/** 公开访问 */
export const anyone: Access = () => true

/** 仅本人或超级管理员（集合级 — 支持 Where 过滤）*/
export const selfOrAdmin: Access = ({ req: { user } }) => {
  if (!user) return false
  if ((user as any).roles?.includes('super-admin')) return true
  // 行级过滤：只允许访问/更新自己
  return { id: { equals: user.id } }
}

// ============================================================
// Admin 集合可见性（严格 boolean-only，不支持 Where）
// ============================================================

/** admin 访问：布尔判断 */
export const adminAccess = ({ req: { user } }: any): boolean => {
  return Boolean(user)
}

/** superAdmin admin 访问：布尔判断 */
export const superAdminAccess = ({ req: { user } }: any): boolean => {
  return (user as any)?.roles?.includes('super-admin') || false
}

// ============================================================
// 字段级 FieldAccess（只允许返回 boolean）
// ============================================================

/** 字段级：仅已登录用户 */
export const authenticatedField: FieldAccess = ({ req: { user } }) => {
  return Boolean(user)
}

/** 字段级：仅超级管理员 */
export const superAdminField: FieldAccess = ({ req: { user } }) => {
  return (user as any)?.roles?.includes('super-admin') || false
}

