    siteName: 'Detwiler Tech',
  },
  robots: {
    index: true,
    follow: true,
  },
}

const orgJsonLd = {
  '@context': 'https://schema.org',
  '@type': 'Organization',
  name: clientEnv.siteName,
  url: clientEnv.siteUrl,
