import { Button } from '@/components/ui/button'
import { Badge } from '@/components/ui/badge'
import { InquiryActions } from '@/components/inquiry/InquiryActions'
import {
  getProductBySlug,
  getRelatedProducts,
  getCategoryBySlug,
  getAllProducts,
} from '@/lib/products'
import { clientEnv } from '@/lib/env'
import { ProductGallery } from '@/components/product/ProductGallery'

export const dynamic = 'force-static'

export function generateStaticParams() {
  return getAllProducts().map((p) => ({ slug: p.slug }))
}

interface PageProps {
  params: Promise<{ slug: string; locale: string }>
}

export async function generateMetadata({ params }: PageProps): Promise<Metadata> {
  const { slug, locale } = await params
  const product = getProductBySlug(slug)
  if (!product) return { title: 'Not Found' }
  const name = product.name[locale as 'en' | 'zh']
  const desc = product.shortDescription?.[locale as 'en' | 'zh'] ?? name
  return {
    title: name,
    description: desc,
    openGraph: {
      title: name,
      description: desc,
      images: product.images.slice(0, 1).map((src) => ({ url: src })),
