input.new_string:
function start() {
  log(`starting next dev on port ${PORT} (distDir=.next-dev) ...`)
  // detached + unref 让子进程脱离父进程,父进程退出不会被 SIGHUP
  const isWindows = os.platform() === 'win32'
  const child = spawn(
    isWindows ? 'npx.cmd' : 'npx',
    ['next', 'dev', '-p', PORT, '-H', '0.0.0.0'],
    {
      cwd: ROOT,
      stdio: 'inherit',
      detached: true,
      env: { ...process.env, NODE_OPTIONS: '--no-deprecation' },
      windowsHide: true,
    },
  )
  // Windows 下 detached 需要让 child 自己开新进程组
  if (isWindows) {
    child.unref()
  }
  log(`dev server spawned, PID=${child.pid}`)
  // 父进程立即退出,不要等子进程
  process.exit(0)
}

