      stdio: 'inherit',
      detached: true,
      shell: isWindows,  // Windows 必须
      env: { ...process.env, NODE_OPTIONS: '--no-deprecation' },
      windowsHide: true,
    },
  )
  child.unref()
  log(`dev server spawned, PID=${child.pid}`)
  // 父进程立即退出,不要等子进程
  process.exit(0)
}

